package main

func run(rows []string) uint64 {
	var hash uint64 = 1469598103934665603
	for _, row := range rows {
		var u, score, flag int
		var i int

		i = 2
		neg := false
		if i < len(row) && row[i] == '-' {
			neg = true
			i++
		}
		for i < len(row) && row[i] >= '0' && row[i] <= '9' {
			u = u*10 + int(row[i]-'0')
			i++
		}
		if neg {
			u = -u
		}

		i += 7
		neg = false
		if i < len(row) && row[i] == '-' {
			neg = true
			i++
		}
		for i < len(row) && row[i] >= '0' && row[i] <= '9' {
			score = score*10 + int(row[i]-'0')
			i++
		}
		if neg {
			score = -score
		}

		i += 6
		neg = false
		if i < len(row) && row[i] == '-' {
			neg = true
			i++
		}
		for i < len(row) && row[i] >= '0' && row[i] <= '9' {
			flag = flag*10 + int(row[i]-'0')
			i++
		}
		if neg {
			flag = -flag
		}

		v := uint64((u & 2047) + score + flag*19)
		hash ^= v + 1
		hash *= 1099511628211
	}
	return hash
}
